module asyn_fifo (
    input wclk, 
    input rclk, 
    input wrstn, 
    input rrstn, 
    input winc, 
    input rinc, 
    input [7:0] wdata, 
    output wfull, 
    output rempty, 
    output [7:0] rdata
);

parameter WIDTH = 8;
parameter DEPTH = 16;

reg [3:0] wptr, rptr;
reg [3:0] wptr_buff, rptr_buff;
reg [3:0] waddr_bin, raddr_bin;
reg [7:0] ram_out;

dual_port_RAM #(.DEPTH(DEPTH), .WIDTH(WIDTH)) ram_inst (
    .wclk(wclk),
    .wenc(winc),
    .waddr(waddr_bin[$clog2(DEPTH)-1:0]),
    .wdata(wdata),
    .rclk(rclk),
    .renc(rinc),
    .raddr(raddr_bin[$clog2(DEPTH)-1:0]),
    .rdata(ram_out)
);

always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        waddr_bin <= 0;
    end else if (winc && !wfull) begin
        waddr_bin <= waddr_bin + 1;
    end
end

always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        raddr_bin <= 0;
    end else if (rinc && !rempty) begin
        raddr_bin <= raddr_bin + 1;
    end
end

always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        wptr_buff <= 0;
    end else begin
        wptr_buff <= wptr;
    end
end
always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        rptr_buff <= 0;
    end else begin
        rptr_buff <= rptr;
    end
end

assign wfull = (wptr == {~rptr[3], rptr[2:0]});
assign rempty = (rptr == wptr);

assign wen = winc && !wfull;
assign ren = rinc && !rempty;
assign rdata = ram_out;
endmodule
